import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a hexadecimal number?", a: "A hexadecimal number is a base-16 number that uses digits 0 through 9 and letters A through F. Each hex digit represents four binary bits, so hex is a compact way to write computer values." },
  { q: "How do you add hexadecimal numbers?", a: "Hex addition works like decimal addition, but carrying happens at 16 instead of 10. For example, F + 1 becomes 10 in hexadecimal because F represents 15." },
  { q: "How do you convert hex to decimal?", a: "Multiply each hex digit by a power of 16 based on its position, then add the values. For example, 2A equals 2 x 16 plus 10, which is 42 in decimal." },
  { q: "Why is hexadecimal used in programming?", a: "Programmers use hexadecimal because it is shorter than binary and maps cleanly to bytes, memory addresses, colors, and low-level data. Two hex digits represent one byte." },
  { q: "What is the difference between hex and binary?", a: "Binary is base 2 and uses 0 and 1. Hexadecimal is base 16 and uses 0-9 plus A-F. Hex is easier for humans to read, while binary is closer to how computers store data." },
];

type Operation = "add" | "subtract" | "multiply" | "divide";

function parseBase(value: string, base: number) {
  const clean = value.trim().replace(/^0x/i, "").replace(/\s+/g, "");
  const pattern = base === 16 ? /^[0-9a-f]+$/i : base === 2 ? /^[01]+$/ : base === 8 ? /^[0-7]+$/ : /^-?\d+$/;
  if (!pattern.test(clean)) return null;
  if (base === 10) return BigInt(clean);
  return BigInt(`${base === 16 ? "0x" : base === 2 ? "0b" : "0o"}${clean}`);
}

function formatHex(value: bigint) {
  return value < 0n ? `-${(-value).toString(16).toUpperCase()}` : value.toString(16).toUpperCase();
}

export default function HexCalculator() {
  const [a, setA] = useState("A");
  const [b, setB] = useState("3");
  const [operation, setOperation] = useState<Operation>("add");
  const [convertValue, setConvertValue] = useState("2A");
  const [convertBase, setConvertBase] = useState("16");

  const calculation = useMemo(() => {
    const left = parseBase(a, 16);
    const right = parseBase(b, 16);
    if (left === null || right === null) return { result: "Invalid hex input", decimal: "", step: "Use digits 0-9 and letters A-F only." };
    if (operation === "divide" && right === 0n) return { result: "Cannot divide by zero", decimal: "", step: "Hex division requires a nonzero divisor." };
    const value = operation === "add" ? left + right : operation === "subtract" ? left - right : operation === "multiply" ? left * right : left / right;
    const symbol = operation === "add" ? "+" : operation === "subtract" ? "-" : operation === "multiply" ? "x" : "/";
    const remainder = operation === "divide" ? left % right : 0n;
    return {
      result: formatHex(value),
      decimal: value.toString(10),
      step: `${a.toUpperCase()} (${left.toString(10)}) ${symbol} ${b.toUpperCase()} (${right.toString(10)}) = ${formatHex(value)}${operation === "divide" && remainder !== 0n ? ` remainder ${formatHex(remainder)}` : ""}`,
    };
  }, [a, b, operation]);

  const conversion = useMemo(() => {
    const value = parseBase(convertValue, Number(convertBase));
    if (value === null) return { hex: "Invalid", decimal: "Invalid", binary: "Invalid", octal: "Invalid" };
    return { hex: formatHex(value), decimal: value.toString(10), binary: value.toString(2), octal: value.toString(8) };
  }, [convertValue, convertBase]);

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all font-mono";

  return (
    <>
      <SEOHead title="Free Hex Calculator Online - Add Subtract Multiply Divide Hex Numbers Instantly | CalcHive" description="Free online hexadecimal calculator. Perform math operations on hex numbers and convert between hex, decimal, binary and octal instantly. 100% free for programmers and students, no signup required." canonical="/hex-calculator" keywords="free hex calculator, hexadecimal calculator online free, hex to decimal converter free, hex addition calculator free, hexadecimal math calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Hexadecimal Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free hex calculator to perform hexadecimal math and convert values between hex, decimal, binary, and octal.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="hex-a" className="text-sm font-semibold text-foreground block mb-2">Hex A</label><input id="hex-a" value={a} onChange={(event) => setA(event.target.value)} className={inputClass} /></div>
            <div><label htmlFor="hex-operation" className="text-sm font-semibold text-foreground block mb-2">Operation</label><select id="hex-operation" value={operation} onChange={(event) => setOperation(event.target.value as Operation)} className={inputClass}><option value="add">Add</option><option value="subtract">Subtract</option><option value="multiply">Multiply</option><option value="divide">Divide</option></select></div>
            <div><label htmlFor="hex-b" className="text-sm font-semibold text-foreground block mb-2">Hex B</label><input id="hex-b" value={b} onChange={(event) => setB(event.target.value)} className={inputClass} /></div>
          </div>
          <motion.div key={`${a}-${b}-${operation}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Hex Result</p>
              <p className="text-5xl font-black text-white tracking-tight break-all" data-testid="result-hex">{calculation.result}</p>
              {calculation.decimal && <p className="text-white/70 text-sm mt-1">Decimal: {calculation.decimal}</p>}
            </div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground font-mono" data-testid="result-steps">{calculation.step}</p></div>
          </motion.div>
        </section>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Base Converter</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
            <div><label htmlFor="convert-value" className="text-sm font-semibold text-foreground block mb-2">Value</label><input id="convert-value" value={convertValue} onChange={(event) => setConvertValue(event.target.value)} className={inputClass} /></div>
            <div><label htmlFor="convert-base" className="text-sm font-semibold text-foreground block mb-2">Input base</label><select id="convert-base" value={convertBase} onChange={(event) => setConvertBase(event.target.value)} className={inputClass}><option value="16">Hexadecimal</option><option value="10">Decimal</option><option value="2">Binary</option><option value="8">Octal</option></select></div>
          </div>
          <div className="grid grid-cols-2 gap-3">{[["Hex", conversion.hex], ["Decimal", conversion.decimal], ["Binary", conversion.binary], ["Octal", conversion.octal]].map(([label, value]) => <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground font-medium">{label}</p><p className="text-lg font-extrabold text-foreground break-all">{value}</p></div>)}</div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Add Subtract Multiply and Divide Hex Numbers for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two hexadecimal values, choose an operation, and this hexadecimal calculator online free tool converts the numbers, performs the math, and shows the result in hex.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Convert Between Hex Decimal Binary and Octal</h2><p className="text-muted-foreground leading-relaxed">The converter translates the same value across base 16, base 10, base 2, and base 8 so you can check programming and computer science work quickly.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Hex Math Tool for Programmers and Students</h2><p className="text-muted-foreground leading-relaxed">Use this hex to decimal converter free and hexadecimal math calculator free for byte values, memory addresses, colors, and class practice.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/hex-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


